async function getIcon(name) {
  return {path: MUSHIC_ICONS_MAP[name]?.path};
}
async function getIconList() {
  return Object.entries(MUSHIC_ICONS_MAP).map(([icon, content]) => ({
    name: icon,
    keywords: content.keywords,
  }));
}

